using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9: HasIndex throws for Cosmos entities. Removed.
            // Manage indexing via the container's indexing policy (Azure Portal/Bicep/Terraform).

            // EF Core 9: Default discriminator renamed from "Discriminator" to "$type".
            // Preserve "Discriminator" so existing 500K documents and direct SQL queries
            // (e.g. c.Discriminator = 'Product') continue to work without a data migration.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id values no longer include the discriminator prefix.
            // Preserve the old "EntityType|KeyValue" format (e.g. "Product|123") so
            // FindAsync and point-reads against existing documents still resolve.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

